const $ = (q) => document.querySelector(q);
const data = {
  tasks:[
    ['📖','15 dk kitap okudun mu?','Eğitim',2,true],['✏️','Ödevlerini yaptın mı?','Eğitim',3,true],['🛏️','Yatağını topladın mı?','Düzen',2,true],['🦷','Dişlerini fırçaladın mı?','Bakım',1,true],['🧸','Oyuncaklarını topladın mı?','Düzen',2,false]
  ],
  rewards:[['🎁','Küçük Sürpriz',10],['🍦','Dondurma Günü',20],['🎮','Oyun Saati Bonusu',30],['🎬','Sinema Günü',50],['👑','Büyük Ödül',100]],
  week:[18,12,20,21,8,10,0]
};
let mode='child';
let logged=localStorage.getItem('elif-v22-login')==='1';
function taskHTML(){return data.tasks.map(t=>`<div class="task"><div class="ic">${t[0]}</div><div><b>${t[1]}</b><small>${t[2]}</small></div><div class="pt">+${t[3]}⭐</div><div class="check ${t[4]?'':'empty'}">${t[4]?'✓':''}</div></div>`).join('')}
function rewardsHTML(){return data.rewards.map(r=>`<div class="reward"><div>${r[0]}</div><b>${r[1]}</b><div class="price">${r[2]}⭐</div></div>`).join('')}
function weekHTML(){return data.week.map((w,i)=>`<div class="day"><div class="star">⭐</div><b>${w}</b><small>${String(19+i).padStart(2,'0')}/05</small></div>`).join('')}
function nav(){return ['🏠 Ana Sayfa','✅ Görevler','🎮 Mini Oyunlar','🗺️ Macera Haritası','🏅 Rozetler','🎁 Ödüller','📅 Haftalık','👤 Profilim'].map((x,i)=>`<button class="${i===0?'active':''}">${x}</button>`).join('')}
function sidebar(){return `<aside class="sidebar"><div class="logoPanel"><div class="brand"><span>Elif</span> <span>Lina</span> <small>★</small></div><div class="tag">Günlük Sorumluluk</div></div><div class="avatarBig">👧🏻</div><div class="switch"><button class="${mode==='child'?'active':''}" onclick="mode='child';renderApp()">Çocuk</button><button class="${mode==='parent'?'active':''}" onclick="mode='parent';renderApp()">Ebeveyn</button></div><nav class="nav">${nav()}</nav><div class="sideGoal"><b>⭐ Günlük hedef</b><p>125 yıldız toplandı</p><button class="logout" onclick="localStorage.removeItem('elif-v22-login');logged=false;render()">Çıkış Yap</button></div></aside>`}
function topbar(){return `<div class="topbar"><div class="hello"><h1>Merhaba Elif Lina! 👋</h1><p>Bugün harika işler seni bekliyor.</p></div><div class="stats"><div class="pill"><span>⭐</span><div><small>Toplam Yıldız</small><span class="num">125</span></div></div><div class="pill"><span>🛡️</span><div><small>Seviye</small><span class="num">4</span></div></div><div class="pill"><span>🔥</span><div><small>Günlük Seri</small><span class="num">7</span></div></div><div class="pill"><span>✅</span><div><small>Görev</small><span class="num">4/5</span></div></div><button class="pill bell">🔔</button><select class="roleSelect" onchange="mode=this.value;renderApp()"><option value="child" ${mode==='child'?'selected':''}>Çocuk Paneli</option><option value="parent" ${mode==='parent'?'selected':''}>Ebeveyn Paneli</option></select></div></div>`}
function hero(){return `<section class="hero"><div><span class="badgeTiny">Bugünün macerası başladı ✨</span><h2>Merhaba Elif Lina! Bugün yıldızları toplamaya hazır mısın?</h2><p>Görevlerini tamamla, macera haritasında ilerle ve sürpriz kutuya bir adım daha yaklaş.</p><div class="heroActions"><button class="btn">Görevlerime Git</button><button class="btn secondary">Haritayı Aç</button></div></div><div class="heroCharacter"><div class="girl">👧🏻</div><div class="heroMini"><div><b>80%</b><small>İlerleme</small></div><div><b>4/5</b><small>Görev</small></div><div><b>+8</b><small>Yıldız</small></div></div></div></section>`}
function childDashboard(){return `<main class="main">${topbar()}${hero()}<div class="grid"><section class="card progressCard"><div><h3>Bugünkü İlerlemen</h3><div class="ring" style="--p:80"><b>80%</b></div></div><div><div class="big">4 / 5 görev</div><p>tamamlandı</p><div class="bar"><i style="width:80%"></i></div></div></section><section class="card chest"><div class="icon">🧰</div><div><h3>Sürpriz Kutu</h3><b>25 / 30 yıldız</b><p>30 yıldız olduğunda kutunu aç!</p><div class="bar"><i style="width:83%"></i></div></div></section><section class="card motivation"><div class="uni">🦄</div><b>Küçük adımlar,<br/>büyük değişimler yaratır! 🌈</b></section><section class="card tall"><h3>Ödüller Dükkanı</h3><div class="rewards">${rewardsHTML()}</div></section><section class="card tall"><h3>Bugünkü Görevlerin <button class="btn secondary" style="float:right;padding:7px 11px">Tümünü Gör</button></h3><div class="tasks">${taskHTML()}</div><div class="taskActions"><button class="btn">Tüm Görevleri Gör</button><button class="btn secondary">Kaydet</button></div></section><section class="card tall"><h3>Mini Oyunlar <button class="btn secondary" style="float:right;padding:7px 11px">Tümünü Gör</button></h3><div class="games"><div class="game"><div class="emoji">🐼</div><b>Eşleştirme</b><small>Hafıza kartlarını bul</small><button>Oyna</button></div><div class="game"><div class="emoji">⭐</div><b>Yıldız Toplama</b><small>Uzayda yıldız yakala</small><button>Oyna</button></div><div class="game"><div class="emoji">🎈</div><b>Balon Patlatma</b><small>Puanlı balonları patlat</small><button>Oyna</button></div><div class="game"><div class="emoji">abc</div><b>Kelime Bulmaca</b><small>Yeni kelimeler öğren</small><button>Oyna</button></div></div></section><section class="card tall wide"><h3>Macera Haritası <button class="btn secondary" style="float:right;padding:7px 11px">Tümünü Gör</button></h3><div class="map"><div class="mount">⛰️</div><div class="castle">🏰</div><div class="path"></div><div class="node n1">1</div><div class="node n2">2</div><div class="node n3">3</div><div class="node n4">4</div><div class="node n5">5</div><div class="treasure">🎁</div></div><b>Seviye 5: Harika!</b><small> Sonraki hedef: 6. seviye</small><div class="bar"><i style="width:68%"></i></div></section><section class="card"><h3>Haftalık Özet <button class="btn secondary" style="float:right;padding:7px 11px">Tümünü Gör</button></h3><div class="week">${weekHTML()}</div><div class="weekTotal">89 ⭐<br/><small>haftalık toplam</small></div></section></div><section class="benefits"><div class="benefit"><span class="e">🛡️</span><div><b>Sorumluluk Bilinci</b><small>Alışkanlık kazan.</small></div></div><div class="benefit"><span class="e">⭐</span><div><b>Motivasyon Artar</b><small>Yıldızla destek.</small></div></div><div class="benefit"><span class="e">🎮</span><div><b>Eğlenceli Öğrenme</b><small>Oyunlarla keşfet.</small></div></div><div class="benefit"><span class="e">⏰</span><div><b>Zaman Yönetimi</b><small>Planlı olmayı öğren.</small></div></div><div class="benefit"><span class="e">🏆</span><div><b>Özgüven Gelişimi</b><small>Başardıkça güven.</small></div></div><div class="benefit"><span class="e">👨‍👩‍👧</span><div><b>Aile Bağı Güçlenir</b><small>Birlikte takip edin.</small></div></div></section><section class="footerCta"><div><b>🏆 Elif Lina ile her gün daha iyiye!</b><p>Görevleri tamamla, yıldızlarını topla, ödülleri kazan.</p></div><button class="btn secondary">Bugünü Kaydet</button></section></main>`}
function parentDashboard(){return `<main class="main parent active">${topbar()}<section class="hero" style="grid-template-columns:1fr"><div><span class="badgeTiny">Ebeveyn Paneli</span><h2>Takip, yönetim ve raporlar tek ekranda.</h2><p>Görevleri düzenleyin, ödülleri yönetin ve haftalık performansı izleyin.</p></div></section><div class="parentGrid"><section class="card"><h3>Tamamlanan Görev</h3><div class="metric">15/20</div><p style="color:var(--green);font-weight:900">%75 başarı</p></section><section class="card"><h3>Toplam Yıldız</h3><div class="metric">125⭐</div><p style="color:var(--green);font-weight:900">+25 bugün</p></section><section class="card"><h3>Günlük Seri</h3><div class="metric">7🔥</div><p>Devam ediyor</p></section><section class="card"><h3>Ortalama</h3><div class="metric">12.5</div><p>yıldız / gün</p></section><section class="card wide"><h3>Son 7 Gün Performansı</h3><div class="chart"><i style="height:70px"></i><i style="height:90px"></i><i style="height:60px"></i><i style="height:105px"></i><i style="height:85px"></i><i style="height:40px"></i><i style="height:65px"></i></div></section><section class="card wide"><h3>Görev Yönetimi</h3><table class="adminTable"><tr><th>Görev</th><th>Kategori</th><th>Puan</th><th>Aktif</th></tr>${data.tasks.map(t=>`<tr><td>${t[0]} ${t[1]}</td><td>${t[2]}</td><td>${t[3]}</td><td><span class="toggle"></span></td></tr>`).join('')}</table><button class="btn" style="margin-top:12px">+ Yeni Görev Ekle</button></section><section class="card wide"><h3>Ödül Yönetimi</h3><table class="adminTable"><tr><th>Ödül</th><th>Gerekli Yıldız</th><th>Durum</th></tr>${data.rewards.map(r=>`<tr><td>${r[0]} ${r[1]}</td><td>${r[2]}</td><td><span class="toggle"></span></td></tr>`).join('')}</table><button class="btn" style="margin-top:12px">+ Yeni Ödül Ekle</button></section><section class="card"><h3>Hızlı Ayarlar</h3><div class="reward"><b>Günlük Limit</b><div></div><span>50</span></div><div class="reward"><b>Kutu Eşiği</b><div></div><span>30</span></div><div class="reward"><b>Bildirim</b><div></div><span class="toggle"></span></div><button class="btn" style="width:100%;margin-top:14px">Kaydet</button></section></div></main>`}
function appShell(){return `<div class="app">${sidebar()}${mode==='child'?childDashboard():parentDashboard()}</div>`}
function login(){return `<div class="loginView"><section class="loginArt"><h1>Elif Lina</h1><p>Günlük Sorumluluk ve Oyunlaştırma Programı</p><div class="loginGirl">👧🏻</div><p>🛡️ Güvenli &nbsp;&nbsp; ⭐ Eğlenceli &nbsp;&nbsp; 🏆 Ödüllü</p></section><section class="loginPanel"><h2>Hoş Geldin! 👋</h2><p>Devam etmek için profil seç.</p><h3>Çocuk Girişi</h3><div class="profileOption active"><span class="face">👧🏻</span><div><b>Elif Lina</b><small>Seviye 4</small></div></div><div class="profileOption"><span class="face">👦🏻</span><div><b>Ali Efe</b><small>Örnek profil</small></div></div><div class="profileOption"><span class="face">👧🏽</span><div><b>Zeynep</b><small>Örnek profil</small></div></div><button class="loginButton" onclick="localStorage.setItem('elif-v22-login','1');logged=true;mode='child';render()">Elif Lina ile Başla</button><button class="loginButton" style="background:linear-gradient(90deg,#6b31d9,#2a74ff)" onclick="localStorage.setItem('elif-v22-login','1');logged=true;mode='parent';render()">Ebeveyn Girişi</button></section></div>`}
function renderApp(){document.getElementById('app').innerHTML=appShell()}
function render(){document.getElementById('app').innerHTML=logged?appShell():login()}
render();
